from collections import deque
def num_islands(grid):
    if not grid: 
        return 0
    m, n = len(grid), len(grid[0])
    grid = [list(row) if isinstance(row, str) else row[:] for row in grid]
    def bfs(r, c):
        q = deque([(r, c)])
        grid[r][c] = '0'
        while q:
            x, y = q.popleft()
            for dx, dy in [(1,0),(-1,0),(0,1),(0,-1)]:
                i, j = x + dx, y + dy
                if 0 <= i < m and 0 <= j < n and grid[i][j] == '1':
                    grid[i][j] = '0'
                    q.append((i, j))
    count = 0
    for i in range(m):
        for j in range(n):
            if grid[i][j] == '1':
                count += 1
                bfs(i, j)
    return count

